const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Gérez l'hôte Linux de l'imprimante — vérifiez son état et celui du système d'exploitation et contrôlez ses services en arrière-plan. Le nettoyage du disque et les réglages système arriveront dans des phases ultérieures."}},view:{monitor:{t:0,b:{t:2,i:[{t:3}],s:"Moniteur"}},services:{t:0,b:{t:2,i:[{t:3}],s:"Services"}},cleanup:{t:0,b:{t:2,i:[{t:3}],s:"Nettoyage"}}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Qu'est-ce que c'est ?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind s'exécute sur le petit ordinateur Linux de l'imprimante (l'hôte). Ce panneau lit l'état en direct de cette machine et de son système d'exploitation pour repérer les problèmes — un processeur en surchauffe, un disque plein, une horloge non synchronisée — sans ouvrir de terminal, et vous laisse contrôler les services en arrière-plan qu'il exécute."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Lisez d'un coup d'œil les cartes de température du processeur, de mémoire, de disque et de réseau."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Surveillez le tableau des principaux processus pour voir ce qui sollicite le processeur en ce moment."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Laissez l'actualisation automatique activée pour une vue en direct, ou désactivez-la et actualisez manuellement."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Termes utilisés ici"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"Lire le moniteur"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Tout est en lecture seule ici. Les barres deviennent ambre au-delà de 75 % et rouges au-delà de 90 %. La température du processeur devient ambre à 70 °C et rouge à 80 °C. L'avertissement de bridage n'apparaît que sur les cartes qui le signalent (principalement Raspberry Pi)."}}},services:{title:{t:0,b:{t:2,i:[{t:3}],s:"Gérer les services"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Chaque ligne est un service systemd. Cliquez sur l'un d'eux pour le démarrer/arrêter/redémarrer, l'activer/le désactiver au démarrage, le masquer, lire son journal ou — pour les services que vous avez installés — supprimer son fichier d'unité. Arrêter ou désactiver un service demande une confirmation. Les services critiques et protégés sont marqués ; les protégés (comme SSH et ce panneau) ne peuvent pas être arrêtés, pour ne pas vous verrouiller dehors."}}},cleanup:{title:{t:0,b:{t:2,i:[{t:3}],s:"Libérer de l'espace disque"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Chaque ligne est d'abord analysée pour montrer ce qu'elle libérerait. Cochez celles à vider et confirmez. Seules les données régénérables sont proposées — le cache de téléchargement apt, l'ancien journal systemd, ~/.cache, vos anciens fichiers /tmp et les journaux pivotés (non actifs). Vos G-code, timelapses et configurations ne sont jamais touchés."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Hôte"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Le petit ordinateur Linux (par ex. un Raspberry Pi ou un BTT CB1) qui exécute Klipper, Moonraker et FilaMind — distinct des microcontrôleurs de l'imprimante."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"Charge moyenne"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Le nombre de processus en attente d'exécution, moyenné sur 1 / 5 / 15 minutes. En gros : une valeur proche du nombre de cœurs indique un processeur occupé ; bien au-dessus indique une surcharge."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Espace disque utilisé comme débordement lorsque la RAM est pleine. Un usage intensif du swap ralentit l'hôte — signe d'un manque de mémoire."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"Bridage (throttling)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Lorsque la carte réduit sa vitesse pour se protéger — généralement à cause d'une alimentation insuffisante (sous-tension) ou d'une surchauffe. Signalé surtout sur Raspberry Pi."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / synchronisation de l'horloge"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Le protocole NTP maintient l'horloge de l'hôte précise. Une horloge non synchronisée peut casser les timelapses, les journaux et les certificats TLS."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"Paramètres régionaux (locale)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Les réglages de langue et de disposition du clavier de l'hôte, utilisés par le système d'exploitation pour le texte, les dates et la disposition du clavier de la console."}}},service:{term:{t:0,b:{t:2,i:[{t:3}],s:"Service (unité)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un programme en arrière-plan géré par systemd — Klipper, Moonraker, le diffuseur de la webcam et la pile réseau s'exécutent tous comme des services."}}},enabled:{term:{t:0,b:{t:2,i:[{t:3}],s:"Activé / désactivé"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Si un service démarre automatiquement au boot. « enabled » démarre au boot ; « disabled » non ; « static » n'est démarré que par un autre service."}}},mask:{term:{t:0,b:{t:2,i:[{t:3}],s:"Masquer (mask)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Une forme plus forte de désactivation — le service ne peut pas du tout être démarré (même par un autre service) tant qu'il n'est pas démasqué. À utiliser avec prudence."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualiser"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualisation automatique"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Lecture de l'état de l'hôte…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"Hôte"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"Nom d'hôte"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"Système d'exploitation"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"Noyau"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"Temps de fonctionnement"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"Processeur"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"Température"}},load:{t:0,b:{t:2,i:[{t:3}],s:"Charge (1·5·15 min)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"Cœurs"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"Bridé"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"Mémoire"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"RAM"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"Disque"}},network:{t:0,b:{t:2,i:[{t:3}],s:"Réseau"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"Interface"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"Adresse IP"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"Wi-Fi"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"Signal"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"Heure et paramètres régionaux"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"Fuseau horaire"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"Synchronisation de l'horloge"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"Synchronisé"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"Synchronisation…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"Désactivé"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Langue"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"Disposition du clavier"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"Principaux processus"}},command:{t:0,b:{t:2,i:[{t:3}],s:"Commande"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"CPU %"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"MÉM %"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}},services:{warning:{t:0,b:{t:2,i:[{t:3}],s:"Arrêter ou désactiver le mauvais service peut mettre l'imprimante hors ligne. Les services critiques sont marqués ; les protégés ne peuvent pas être arrêtés."}},search:{t:0,b:{t:2,i:[{t:3}],s:"Rechercher des services…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualiser"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Liste des services…"}},loadingDetail:{t:0,b:{t:2,i:[{t:3}],s:"Lecture du service…"}},loadingLogs:{t:0,b:{t:2,i:[{t:3}],s:"Lecture du journal…"}},summary:{t:0,b:{t:2,i:[{t:4,k:"total"},{t:3,v:" services · "},{t:4,k:"active"},{t:3,v:" actifs · "},{t:4,k:"failed"},{t:3,v:" en échec"}]}},filter:{all:{t:0,b:{t:2,i:[{t:3}],s:"Tous"}},active:{t:0,b:{t:2,i:[{t:3}],s:"Actifs"}},inactive:{t:0,b:{t:2,i:[{t:3}],s:"Inactifs"}},failed:{t:0,b:{t:2,i:[{t:3}],s:"En échec"}},enabled:{t:0,b:{t:2,i:[{t:3}],s:"Activés"}}},stateActive:{t:0,b:{t:2,i:[{t:3}],s:"Actif"}},stateInactive:{t:0,b:{t:2,i:[{t:3}],s:"Inactif"}},stateFailed:{t:0,b:{t:2,i:[{t:3}],s:"En échec"}},critical:{t:0,b:{t:2,i:[{t:3}],s:"Critique"}},protected:{t:0,b:{t:2,i:[{t:3}],s:"Protégé"}},state:{t:0,b:{t:2,i:[{t:3}],s:"État"}},startup:{t:0,b:{t:2,i:[{t:3}],s:"Démarrage"}},unitFile:{t:0,b:{t:2,i:[{t:3}],s:"Fichier d'unité"}},action:{start:{t:0,b:{t:2,i:[{t:3}],s:"Démarrer"}},stop:{t:0,b:{t:2,i:[{t:3}],s:"Arrêter"}},restart:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer"}},enable:{t:0,b:{t:2,i:[{t:3}],s:"Activer"}},disable:{t:0,b:{t:2,i:[{t:3}],s:"Désactiver"}},mask:{t:0,b:{t:2,i:[{t:3}],s:"Masquer"}},unmask:{t:0,b:{t:2,i:[{t:3}],s:"Démasquer"}}},actionOk:{t:0,b:{t:2,i:[{t:4,k:"action"},{t:3,v:" terminé."}]}},confirmAction:{t:0,b:{t:2,i:[{t:4,k:"action"},{t:3,v:" « "},{t:4,k:"name"},{t:3,v:" » ?"}]}},confirmYes:{t:0,b:{t:2,i:[{t:3}],s:"Oui, faire"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Annuler"}},deleteUnit:{t:0,b:{t:2,i:[{t:3}],s:"Supprimer le fichier d'unité…"}},deletePrompt:{t:0,b:{t:2,i:[{t:3,v:"Cela supprime définitivement le fichier d'unité. Tapez « "},{t:4,k:"name"},{t:3,v:" » pour confirmer."}]}},deleteConfirm:{t:0,b:{t:2,i:[{t:3}],s:"Supprimer définitivement"}},deleted:{t:0,b:{t:2,i:[{t:3}],s:"Fichier d'unité supprimé."}},logs:{t:0,b:{t:2,i:[{t:3}],s:"Journal récent"}},noLogs:{t:0,b:{t:2,i:[{t:3}],s:"Aucune sortie de journal."}}},cleanup:{subtitle:{t:0,b:{t:2,i:[{t:3}],s:"Cochez ce qu'il faut supprimer, puis nettoyez. Caches et anciens journaux uniquement — vos impressions et configurations restent intactes."}},rescan:{t:0,b:{t:2,i:[{t:3}],s:"Réanalyser"}},scanning:{t:0,b:{t:2,i:[{t:3}],s:"Analyse du disque…"}},na:{t:0,b:{t:2,i:[{t:3}],s:"n/d"}},items:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" fichiers"}]}},freed:{t:0,b:{t:2,i:[{t:4,k:"size"},{t:3,v:" libérés."}]}},selectedTotal:{t:0,b:{t:2,i:[{t:3,v:"Sélectionné : "},{t:4,k:"size"}]}},clean:{t:0,b:{t:2,i:[{t:3}],s:"Nettoyer la sélection"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Supprimer les éléments sélectionnés ?"}},confirmYes:{t:0,b:{t:2,i:[{t:3}],s:"Oui, nettoyer"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Annuler"}},running:{t:0,b:{t:2,i:[{t:3}],s:"Nettoyage…"}},targets:{apt:{label:{t:0,b:{t:2,i:[{t:3}],s:"Cache de paquets"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Fichiers d'installation .deb téléchargés dont apt n'a plus besoin."}}},journal:{label:{t:0,b:{t:2,i:[{t:3}],s:"Journal système"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Anciens journaux systemd — réduits aux 50 derniers Mo."}}},cache:{label:{t:0,b:{t:2,i:[{t:3}],s:"Cache utilisateur"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Fichiers régénérables dans ~/.cache (miniatures, pip, etc.)."}}},tmp:{label:{t:0,b:{t:2,i:[{t:3}],s:"Fichiers temporaires"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Vos propres fichiers dans /tmp de plus d'un jour."}}},logs:{label:{t:0,b:{t:2,i:[{t:3}],s:"Journaux pivotés"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Anciens journaux Klipper/Moonraker pivotés (le journal actif est conservé)."}}}}}}};export{t as default};
